Box( modifier = Modifier .weight(1f) .height(60.dp) .padding(horizontal = 33.dp) .clip(RoundedCornerShape(12.dp)) .background( if (isSelected) { MaterialTheme.colorScheme.primaryContainer } else { Color.Transparent } ) .clickable { onTabSelected(item.index) }, contentAlignment = Alignment.Center ) { Column(horizontalAlignment = Alignment.CenterHorizontally) { if(item.index != 0) { Spacer(modifier = Modifier.height(8.dp)) } Icon( painter = painterResource(id = item.iconRes), contentDescription = item.label, modifier = Modifier.size(item.iconSize), tint = contentColor ) if (item.index != 0) { Spacer(modifier = Modifier.height(5.dp)) } Text( text = item.label, fontSize = 11.sp, color = contentColor ) } } } } }

