            // 实时预览
            Text(
                text = appString(context, language, R.string.real_time_preview),
                color = colorScheme.onPrimaryContainer,
                style = PageBodyText
            )
            Spacer(modifier = Modifier.height(8.dp))
            Box(
                modifier = Modifier
                    .fillMaxWidth()
                    .height(150.dp)
                    .shadow(6.dp, RoundedCornerShape(20.dp), clip = false)
                    .clip(RoundedCornerShape(20.dp))
                    .background(MaterialTheme.colorScheme.surface)
                    .border(
                        width = 3.dp,
                        color = MaterialTheme.colorScheme.outline,
                        shape = RoundedCornerShape(20.dp)
                    )
                    .padding(16.dp)
                    .verticalScroll(rememberScrollState())

            ) {
                if (previewText.isEmpty()) {
                    Text(
                        text = appString(context, language, R.string.output_box_hint),
                        color = MaterialTheme.colorScheme.onPrimaryContainer.copy(alpha = 0.5f),
                        style = PageBodyText
                    )
                } else {
                    Text(
                        text = previewText,
                        style = previewTextStyle.copy(
                            fontSize = selectedSize.sp,
                            color = textColor,
                            letterSpacing = previewLetterSpacing
                        ),
                        modifier = Modifier.fillMaxWidth()
                    )
                }
            }

            Spacer(modifier = Modifier.height(20.dp))

            // 导出
            Row(
                modifier = Modifier.fillMaxWidth(),
                horizontalArrangement = Arrangement.SpaceEvenly,
                verticalAlignment = Alignment.CenterVertically
            ) {

                Button(
                    onClick = {
                        if (previewText.isNotEmpty()) {
                            exportAsPng(
                                context,
                                previewText,
                                selectedSize,
                                textColor,
                                selectedFont,
                                spacingMultiplier
                            )
                        } else {
                            Toast.makeText(
                                context,
