                                    context,
                                    language,
                                    R.string.converter_export_empty_hint
                                ),
                                Toast.LENGTH_SHORT
                            ).show()
                        }
                    },
                    modifier = Modifier
                        .width(110.dp)
                        .defaultMinSize(minHeight = 30.dp),
                    shape = RoundedCornerShape(18.dp),
                    colors = ButtonDefaults.buttonColors(
                        containerColor = MaterialTheme.colorScheme.primary
                    ),
                    elevation = ButtonDefaults.buttonElevation(
                        defaultElevation = 4.dp,
                        pressedElevation = 6.dp,
                        focusedElevation = 4.dp,
                        hoveredElevation = 4.dp,
                        disabledElevation = 0.dp
                    ),
                    contentPadding = PaddingValues(
                        horizontal = 10.dp,
                        vertical = 4.dp
                    )
                ) {
                    Text(
                        text = appString(
                            context,
                            language,
                            R.string.png_export_button
                        ),
                        style = InfoAndBottomBarLabelText
                    )
                }

                Button(
                    onClick = {
                        if (previewText.isNotEmpty()) {
                            exportAsSvg(
                                context,
                                previewText,
                                selectedSize,
                                textColor,
                                selectedFont,
                                spacingMultiplier
                            )
                        } else {
                            Toast.makeText(
                                context,
                                appString(
                                    context,
                                    language,
                                    R.string.converter_export_empty_hint
                                ),
                                Toast.LENGTH_SHORT
                            ).show()
                        }
                    },
                    modifier = Modifier
                        .width(110.dp)
                        .defaultMinSize(minHeight = 30.dp),
                    shape = RoundedCornerShape(18.dp),
                    colors = ButtonDefaults.buttonColors(
                        containerColor = MaterialTheme.colorScheme.primary
                    ),
                    elevation = ButtonDefaults.buttonElevation(
                        defaultElevation = 3.dp,
                        pressedElevation = 6.dp,
                        focusedElevation = 4.dp,
                        hoveredElevation = 4.dp,
                        disabledElevation = 0.dp
                    ),
                    contentPadding = PaddingValues(
                        horizontal = 10.dp,
                        vertical = 4.dp
                    )
                ) {

                    Text(
                        text = appString(
                            context,
                            language,
                            R.string.svg_export_button
                        ),
                        style = InfoAndBottomBarLabelText
                    )
                }
            }

            Spacer(modifier = Modifier.height(20.dp))
            Text(
                text = appString(context, language, R.string.converter_export_hint),
                color = colorScheme.onPrimaryContainer.copy(alpha = 0.5f),
                style = PageBodyText
            )
        }
    }
}


