Spacer(modifier = Modifier.width(8.dp)) Text( text = item.name, style = InfoAndBottomBarLabelText, color = MaterialTheme.colorScheme.onPrimaryContainer, modifier = Modifier.padding(start = 4.dp) ) } }
val sampleItems = listOf( WikiItem( "0001", 2, "蔷薇的魔女 Gertrud", "Gertrud", null, "蔷薇的魔女，原名格特鲁德，是一位拥有强大力量的魔女。她以其独特的能力和神秘的背景而闻名于世。蔷薇的魔女在历史上留下了许多传说和故事，她的存在一直是人们津津乐道的话题。", externalLinks = listOf(null), version = 1 ), WikiItem( "0002", 1, "鹿目圆 Kaname Madoka", "Kaname Madoka", null, "鹿目圆香是《魔法少女小圆》中的主角之一，她是一个普通的初中生，后来成为了一名魔法少女。她以其善良、勇敢和坚定的性格赢得了许多粉丝的喜爱。鹿目圆香在故事中经历了许多挑战和冒险，她的成长和变化是整个故事的重要组成部分。", externalLinks = listOf(null), version = 1 ), WikiItem( "0003", 0, "魔法少女小圆 Puella Magi Madoka Magica", "Puella Magi Madoka Magica", null, "《魔法少女小圆》是一部由SHAFT制作的原创动画系列，讲述了一个普通的初中生鹿目圆香成为魔法少女后所经历的冒险和挑战。该系列以其独特的故事情节、深刻的主题和精美的动画风格而受到广泛赞誉。它探讨了希望、绝望、牺牲和人性的复杂关系，成为了现代动画中的经典之作。", externalLinks = listOf(null), version = 1 ) )
