@Composable
fun SettingsScreen(
    selectedTab: Int = 2,
    onTabSelected: (Int) -> Unit = {},
    switchSelected: Boolean,
    onThemeChange: (Boolean) -> Unit = {},
    language: AppLanguage = AppLanguage.ZH,
    onLanguageChange: (AppLanguage) -> Unit = {}
) {
    var isDarkTheme by remember { mutableStateOf(switchSelected) }
    val languageOptions = listOf(
        LanguageOption("中文", AppLanguage.ZH, true),
        LanguageOption("English", AppLanguage.EN, true),
        LanguageOption("日本語", null, false)
    )
    var selectedLanguage by remember { mutableStateOf(language) }

    LaunchedEffect(switchSelected) {
        isDarkTheme = switchSelected
    }

    LaunchedEffect(language) {
        selectedLanguage = language
    }

    val context = LocalContext.current
    val uriHandler = LocalUriHandler.current

    fun openUri(url: String) {
        uriHandler.openUri(url)
    }

    Scaffold(
        bottomBar = {
            BottomBar(
                selectedTab = selectedTab,
                onTabSelected = onTabSelected,
                language = selectedLanguage
            )
        }
    ) { paddingValues ->
        Column(
            modifier = Modifier
                .fillMaxSize()
                .padding(paddingValues)
                .padding(horizontal = 30.dp, vertical = 50.dp)
        ) {
            Text(
                text = appString(context, selectedLanguage, R.string.settings_title),
                style = PageTitle,
                color = MaterialTheme.colorScheme.onPrimaryContainer,
                letterSpacing = 3.sp
            )
            Spacer(modifier = Modifier.height(40.dp))
            Row(
                modifier = Modifier
                    .padding(horizontal = 15.dp)
                    .fillMaxWidth()
                    .height(50.dp),
                verticalAlignment = Alignment.CenterVertically
            ) {
                Image(
                    painter = painterResource(id = R.drawable.dark_mode),
                    contentDescription = appString(context, selectedLanguage, R.string.content_desc_dark_mode),
                    colorFilter = ColorFilter.tint(MaterialTheme.colorScheme.onPrimaryContainer)
                )
                Spacer(modifier = Modifier.width(15.dp))
                Text(
                    text = appString(context, selectedLanguage, R.string.settings_dark_mode),
                    style = SettingLabelText,
                    color = MaterialTheme.colorScheme.onPrimaryContainer,
                    letterSpacing = 1.5.sp
                )
                Spacer(modifier = Modifier.weight(1f))
                FixedThumbSwitch(
                    checked = isDarkTheme,
                    onCheckedChange = { newValue ->
                        isDarkTheme = newValue
                        onThemeChange(newValue)
                    }
                )
            }
            Spacer(modifier = Modifier.height(20.dp))
            Row(
                modifier = Modifier
                    .padding(horizontal = 12.dp)
                    .fillMaxWidth()
                    .height(57.dp),
                verticalAlignment = Alignment.CenterVertically
            ) {
                Image(
                    painter = painterResource(id = R.drawable.language_setting_icon),
                    contentDescription = appString(context, selectedLanguage, R.string.content_desc_language_setting),
                    colorFilter = ColorFilter.tint(MaterialTheme.colorScheme.onPrimaryContainer)
                )
                Spacer(modifier = Modifier.width(12.dp))
                Text(
                    text = appString(context, selectedLanguage, R.string.settings_language_label),
                    style = SettingLabelText,
                    color = MaterialTheme.colorScheme.onPrimaryContainer,
                    letterSpacing = 1.5.sp
                )
            }
            Spacer(modifier = Modifier.height(10.dp))
            Row(
                modifier = Modifier
                    .padding(horizontal = 30.dp)
                    .fillMaxWidth()
                    .height(57.dp),
                verticalAlignment = Alignment.CenterVertically,
                horizontalArrangement = Arrangement.SpaceBetween
            ) {
                languageOptions.forEach { option ->
                    Row(
                        verticalAlignment = Alignment.CenterVertically,
                        modifier = Modifier
                            .padding(end = 20.dp)
                            .then(
                                if (option.isEnabled) {
                                    Modifier.clickable {
                                        option.language?.let {
                                            selectedLanguage = it
                                            onLanguageChange(it)
                                        }
                                    }
                                } else {
                                    Modifier
                                }
                            )
                    ) {
                        Box(
                            modifier = Modifier
                                .size(20.dp)
