package com.example.madodict.wiki.data.repository

import com.example.madodict.wiki.data.db.WikiDao
import com.example.madodict.wiki.data.db.WikiItemEntity
import com.example.madodict.wiki.data.json.ExternalLinkJson
import com.google.gson.Gson
import com.google.gson.reflect.TypeToken

data class WikiItem(
    val entryId: String,
    val category: Int,
    val name: String,
    val enName: String?,
    val imagePath: String?,
    val content: String,
    val externalLinks: List<Nothing?>,
    val version: Int
)

class WikiRepository(private val dao: WikiDao) {

    private val gson = Gson()
    private val linkListType = object : TypeToken<List<ExternalLinkJson>>() {}.type

    // 搜索条目，支持模糊匹配，返回列表
    suspend fun search(keyword: String): List<WikiItem> =
        dao.searchEntries(keyword).map { it.toModel() }

    // 获取所有条目，返回列表
    suspend fun getAll(): List<WikiItem> =
        dao.getAllEntries().map { it.toModel() }

    // 获取随机条目，返回单个条目
    suspend fun getRandom(): WikiItem? =
        dao.getRandomEntry()?.toModel()

    // 按id获取条目详情，返回单个条目
    suspend fun getById(entryId: String): WikiItem? =
        dao.getEntryById(entryId)?.toModel()

    private fun WikiItemEntity.toModel() = WikiItem(
        entryId = entryId,
        category = category,
        name = name,
        enName = enName,
        imagePath = imagePath,
        content = content,
        externalLinks = if (externalLinksJson.isNullOrEmpty()) emptyList()
        else gson.fromJson(externalLinksJson, linkListType),
        version = version
    )
}

package com.example.madodict.wiki.data.repository

import com.example.madodict.wiki.data.db.WikiDao
import com.example.madodict.wiki.data.db.WikiItemEntity
import com.example.madodict.wiki.data.json.ExternalLinkJson
import com.google.gson.Gson
import com.google.gson.reflect.TypeToken

data class WikiItem(
    val entryId: String,
    val category: Int,
    val name: String,
    val enName: String?,
    val imagePath: String?,
    val content: String,
    val externalLinks: List<ExternalLinkJson>,
    val version: Int
)

class WikiRepository(private val dao: WikiDao) {

    private val gson = Gson()
    private val linkListType = object : TypeToken<List<ExternalLinkJson>>() {}.type

    // 搜索条目，支持模糊匹配，返回列表
    suspend fun search(keyword: String): List<WikiItem> =
        dao.searchEntries(buildFtsQuery(keyword)).map { it.toModel() }

    // 获取所有条目，返回列表
    suspend fun getAll(): List<WikiItem> =
        dao.getAllEntries().map { it.toModel() }

    // 获取随机条目，返回单个条目
    suspend fun getRandom(): WikiItem? =
        dao.getRandomEntry()?.toModel()

    // 按id获取条目详情，返回单个条目
    suspend fun getById(entryId: String): WikiItem? =
        dao.getEntryById(entryId)?.toModel()

    private fun WikiItemEntity.toModel() = WikiItem(
        entryId = entryId,
        category = category,
        name = name,
        enName = enName,
        imagePath = imagePath,
        content = content,
        externalLinks = if (externalLinksJson.isNullOrEmpty()) emptyList()
        else gson.fromJson(externalLinksJson, linkListType),
        version = version
    )

    private fun buildFtsQuery(keyword: String): String =
        keyword.trim()
            .split(Regex("\\s+"))
            .filter { it.isNotBlank() }
            .joinToString(" ") { "${it}*" }
}

package com.example.madodict.wiki.viewmodel

import androidx.lifecycle.ViewModel
import androidx.lifecycle.ViewModelProvider
import com.example.madodict.wiki.data.repository.WikiItem
import com.example.madodict.wiki.data.repository.WikiRepository
import kotlinx.coroutines.flow.MutableStateFlow
import kotlinx.coroutines.flow.StateFlow
import kotlinx.coroutines.flow.asStateFlow
import kotlinx.coroutines.launch


// 搜索页 UI 状态
data class SearchUiState(
    val keyword: String = "",
    val lastViewedItem: WikiItem? = null
)

// 列表页UI状态
sealed class ListUiState {
    data object Idle : ListUiState()
    data object Loading : ListUiState()
    data class Success(val items: List<WikiItem>) : ListUiState()
    data class Error(val message: String) : ListUiState()
}

// 详情页UI状态
sealed class DetailUiState {
    data object Idle : DetailUiState()
    data object Loading : DetailUiState()
    data class Success(val item: WikiItem) : DetailUiState()
    data class Error(val message: String) : DetailUiState()
}

class WikiViewModel(
    private val repository: WikiRepository
) : ViewModel() {

    // 搜索页状态
    private val _searchUiState = MutableStateFlow(SearchUiState())
    val searchUiState: StateFlow<SearchUiState> = _searchUiState.asStateFlow()

    //列表页状态
    private val _listUiState = MutableStateFlow<ListUiState>(ListUiState.Idle)
    val listUiState: StateFlow<ListUiState> = _listUiState.asStateFlow()

    // 详情页状态
    private val _detailUiState = MutableStateFlow<DetailUiState>(DetailUiState.Idle)
    val detailUiState: StateFlow<DetailUiState> = _detailUiState.asStateFlow()

    // 搜索页操作
    fun onKeywordChange(keyword: String) {
        _searchUiState.value = _searchUiState.value.copy(keyword = keyword)
    }

    fun search() {
        val keyword = _searchUiState.value.keyword.trim()
        if (keyword.isEmpty()) return
        viewModelScope.launch {
            _listUiState.value = ListUiState.Loading
            _listUiState.value = try {
                ListUiState.Success(repository.search(keyword))
            } catch (e: Exception) {
                ListUiState.Error(e.message ?: "搜索失败")
            }
        }
    }

    fun loadAll() {
        viewModelScope.launch {
            _listUiState.value = ListUiState.Loading
            _listUiState.value = try {
                ListUiState.Success(repository.getAll())
            } catch (e: Exception) {
                ListUiState.Error(e.message ?: "加载失败")
            }
        }
    }

    // 随机跳转：直接返回条目，由调用方负责导航
    fun loadRandom(onResult: (WikiItem?) -> Unit) {
        viewModelScope.launch {
            onResult(
                try { repository.getRandom() }
                catch (e: Exception) { null }
            )
        }
    }

    // 详情页操作
    fun loadDetail(entryId: String) {
        viewModelScope.launch {
            _detailUiState.value = DetailUiState.Loading
            _detailUiState.value = try {
                val item = repository.getById(entryId)
                if (item != null) {
                    // 加载成功时同步记录为"上次浏览"
                    _searchUiState.value = _searchUiState.value.copy(lastViewedItem = item)
                    DetailUiState.Success(item)
                } else {
                    DetailUiState.Error("条目不存在")
                }
            } catch (e: Exception) {
                DetailUiState.Error(e.message ?: "加载失败")
            }
        }
    }

    // 列表页返回搜索页时重置列表状态
    fun resetListState() {
        _listUiState.value = ListUiState.Idle
    }

    // 详情页返回列表页时重置详情状态
    fun resetDetailState() {
        _detailUiState.value = DetailUiState.Idle
    }
}

class WikiViewModelFactory(
    private val repository: WikiRepository
) : ViewModelProvider.Factory {
    @Suppress("UNCHECKED_CAST")
    override fun <T : ViewModel> create(modelClass: Class<T>): T {
        if (modelClass.isAssignableFrom(WikiViewModel::class.java)) {
            return WikiViewModel(repository) as T
        }
        throw IllegalArgumentException("Unknown ViewModel class: ${modelClass.name}")
    }
}

